Add-Type -A PresentationFramework,WindowsBase;$u='https://files.catbox.moe/gsz444.png';[xml]$x="<Window xmlns='http://schemas.microsoft.com/winfx/2006/xaml/presentation' WindowStyle='None' Topmost='True' Background='#c00000' WindowState='Maximized' Cursor='None' ShowInTaskbar='False'><Grid Margin='150,120,0,0'><StackPanel HorizontalAlignment='Left' VerticalAlignment='Top'><TextBlock Text='&gt;:(' FontSize='140' Foreground='White' FontFamily='Segoe UI' Margin='0,0,0,20'/><TextBlock Text='Your PC ran into a problem and needs to restart. We&apos;re just' FontSize='36' Foreground='White' FontFamily='Segoe UI Light'/><TextBlock Text='collecting some error info, and then we&apos;ll restart for you.' FontSize='36' Foreground='White' FontFamily='Segoe UI Light' Margin='0,0,0,40'/><TextBlock Name='P' Text='0% complete' FontSize='36' Foreground='White' FontFamily='Segoe UI Light' Margin='0,0,0,40'/><StackPanel Orientation='Horizontal'><Image Source='$u' Width='110' Height='110' Margin='0,0,20,0'/><StackPanel VerticalAlignment='Center'><TextBlock Text='For more information about this issue and possible fixes, visit https://www.windows.com/stopcode' FontSize='16' Foreground='White' FontFamily='Segoe UI' Margin='0,0,0,10'/><TextBlock Text='If you call a support person, give them this info:' FontSize='14' Foreground='White' FontFamily='Segoe UI'/><TextBlock Text='Stop code: DRIVER_IRQL_NOT_LESS_OR_EQUAL' FontSize='14' Foreground='White' FontFamily='Segoe UI'/></StackPanel></StackPanel></StackPanel></Grid></Window>";$w=[Windows.Markup.XamlReader]::Load([System.Xml.XmlNodeReader]::new($x));$p=$w.FindName('P');$w.Add_Closing({param($s,$e) $e.Cancel=$true});$w.Add_KeyDown({param($s,$e) if($e.Key -eq 'End'){$w.Hide();exit}});$script:i=0;$t=New-Object System.Windows.Threading.DispatcherTimer;$t.Interval=[TimeSpan]::FromSeconds(5);$t.Add_Tick({if($script:i -lt 100){$script:i+=(Get-Random -Min 1 -Max 3);if($script:i -gt 100){$script:i=100};$p.Text="$script:i% complete"}});$t.Start();$w.ShowDialog()
